from __future__ import annotations

REQUIRED_READINESS_CHECKS = (
    "http_accepting_requests",
    "critical_dependencies_reachable",
    "required_migrations_applied",
    "minimal_real_request_served",
)


def missing_readiness_checks(checks: list[str] | tuple[str, ...] | set[str]) -> tuple[str, ...]:
    provided = set(checks)
    return tuple(check for check in REQUIRED_READINESS_CHECKS if check not in provided)


def readiness_contract_is_satisfied(checks: list[str] | tuple[str, ...] | set[str]) -> bool:
    return not missing_readiness_checks(checks)

import unittest

from compose_zero_downtime.health_contract import (
    REQUIRED_READINESS_CHECKS,
    missing_readiness_checks,
    readiness_contract_is_satisfied,
)


class HealthContractTests(unittest.TestCase):
    def test_complete_contract_is_satisfied(self):
        self.assertTrue(readiness_contract_is_satisfied(REQUIRED_READINESS_CHECKS))

    def test_missing_checks_are_reported(self):
        missing = missing_readiness_checks({"http_accepting_requests"})

        self.assertIn("critical_dependencies_reachable", missing)
        self.assertIn("minimal_real_request_served", missing)


if __name__ == "__main__":
    unittest.main()

from __future__ import annotations


def nginx_reload_commands(*, validate_config: bool = True) -> tuple[list[str], list[str]]:
    reload_command = ["nginx", "-s", "reload"]
    if validate_config:
        reload_command = ["nginx", "-t", "&&", *reload_command]
    fallback_command = ["docker", "compose", "restart", "nginx"]
    return reload_command, fallback_command


def reload_is_preferred_over_restart(commands: tuple[list[str], list[str]]) -> bool:
    reload_command, fallback_command = commands
    return "reload" in reload_command and "restart" in fallback_command

import unittest

from compose_zero_downtime.nginx_reload import nginx_reload_commands, reload_is_preferred_over_restart


class NginxReloadTests(unittest.TestCase):
    def test_reload_plan_validates_config_before_reload(self):
        reload_command, fallback_command = nginx_reload_commands(validate_config=True)

        self.assertIn("-t", reload_command)
        self.assertIn("reload", reload_command)
        self.assertIn("restart", fallback_command)

    def test_reload_is_preferred_over_restart(self):
        self.assertTrue(reload_is_preferred_over_restart(nginx_reload_commands()))


if __name__ == "__main__":
    unittest.main()

from __future__ import annotations

REQUIRED_DEPLOY_ENV_VARS = (
    "DEPLOY_HOST",
    "DEPLOY_USER",
    "DEPLOY_PATH",
    "APP_IMAGE",
    "APP_PORT",
)


def missing_deploy_env_vars(env: dict[str, str]) -> tuple[str, ...]:
    return tuple(name for name in REQUIRED_DEPLOY_ENV_VARS if not env.get(name))


def deploy_env_is_complete(env: dict[str, str]) -> bool:
    return not missing_deploy_env_vars(env)

import unittest

from compose_zero_downtime.deploy_env import REQUIRED_DEPLOY_ENV_VARS, deploy_env_is_complete, missing_deploy_env_vars


class DeployEnvTests(unittest.TestCase):
    def test_complete_env_passes(self):
        self.assertTrue(deploy_env_is_complete({name: "value" for name in REQUIRED_DEPLOY_ENV_VARS}))

    def test_missing_env_vars_are_reported(self):
        missing = missing_deploy_env_vars({"DEPLOY_HOST": "example.com"})

        self.assertIn("APP_IMAGE", missing)
        self.assertIn("DEPLOY_PATH", missing)


if __name__ == "__main__":
    unittest.main()

